INSERT INTO `tasks` VALUES (31,1,'video','Watch Samsung Galaxy Z Fold7 Launch Video','شاهد فيديو إطلاق Samsung Galaxy Z Fold7','Watch the official launch video for the new Samsung Galaxy Z Fold7 and answer questions','شاهد فيديو الإطلاق الرسمي لـ Samsung Galaxy Z Fold7 الجديد وأجب على الأسئلة',25.00,10000.00,400,2,1000.00,'easy',1,'active',NULL,NULL,NULL,NULL,'[\"tier1\",\"tier2\",\"tier3\"]',0,0,NULL,'quiz',80,80,'{\"videoUrl\": \"https://www.youtube.com/watch?v=rNDHl_1fYTE\", \"duration\": 36}','2025-11-10 13:15:55','2025-11-11 22:05:44','2025-11-10 13:15:55',NULL),(42,12,'video','Watch Orange Egypt Best iPhone Price Campaign','شاهد حملة أورانج مصر لأفضل سعر آيفون','Watch Orange Egypt\'s campaign highlighting the best iPhone prices in Egypt.','شاهد حملة أورانج مصر التي تسلط الضوء على أفضل أسعار آيفون في مصر.',28.00,28000.00,1000,0,5000.00,'easy',1,'active',NULL,NULL,NULL,NULL,NULL,0,0,NULL,'automatic',80,80,'{\"videoUrl\": \"https://www.youtube.com/watch?v=LIr8C5Sirxs\", \"duration\": 40}','2025-11-11 21:33:04','2025-11-11 22:05:44',NULL,NULL),(43,3,'video','Watch Powerade Egypt featuring Lamine Yamal','شاهد حملة باوريد مصر مع لامين يامال','Watch Coca-Cola Egypt\'s Powerade campaign featuring Spanish football star Lamine Yamal.','شاهد حملة باوريد من كوكاكولا مصر مع نجم كرة القدم الإسباني لامين يامال.',32.00,25600.00,800,0,5000.00,'medium',1,'active',NULL,NULL,NULL,NULL,NULL,0,0,NULL,'automatic',80,80,'{\"videoUrl\": \"https://www.youtube.com/watch?v=VrZalP1eBPQ\", \"duration\": 50}','2025-11-11 21:33:04','2025-11-11 22:05:44',NULL,NULL),(44,13,'video','Watch Grand Egyptian Museum x Mansour Campaign','شاهد حملة المتحف المصري الكبير مع منصور','Watch the cinematic tribute to Egyptian heritage by Mansour Automotive and the Grand Egyptian Museum.','شاهد التحية السينمائية للتراث المصري من منصور أوتوموتيف والمتحف المصري الكبير.',35.00,17500.00,500,0,5000.00,'medium',2,'active',NULL,NULL,NULL,NULL,NULL,0,0,NULL,'automatic',80,80,'{\"videoUrl\": \"https://www.youtube.com/w