INSERT INTO `task_questions` VALUES (101,31,'What is the main feature of Galaxy Z Fold7?','ما هي الميزة الرئيسية لـ Galaxy Z Fold7؟',1,'multiple_choice','Water resistance','مقاومة الماء','Foldable screen','شاشة قابلة للطي','Wireless charging','شحن لاسلكي','5G connectivity','اتصال 5G','B','The foldable screen is the signature feature','الشاشة القابلة للطي هي الميزة المميزة',NULL,'2025-11-10 13:16:25'),(102,31,'What type of screen does it have?','ما نوع الشاشة؟',2,'multiple_choice','LCD','LCD','OLED','OLED','Dynamic AMOLED','Dynamic AMOLED','IPS','IPS','C','Samsung uses Dynamic AMOLED technology','تستخدم سامسونج تقنية Dynamic AMOLED',NULL,'2025-11-10 13:16:25'),(105,31,'What is the brand name of the device?','ما هو اسم العلامة التجارية للجهاز؟',3,'multiple_choice','Samsung','سامسونج','Apple','آبل','Huawei','هواوي','Xiaomi','شاومي','A',NULL,NULL,NULL,'2025-11-10 16:34:35'),(106,31,'What is the main innovation highlighted?','ما هو الابتكار الرئيسي المميز؟',4,'multiple_choice','Foldable design','تصميم قابل للطي','Waterproof','مقاوم للماء','5G speed','سرعة 5G','Wireless charging','شحن لاسلكي','A',NULL,NULL,NULL,'2025-11-10 16:34:35'),(107,31,'What series does this phone belong to?','إلى أي سلسلة ينتمي هذا الهاتف؟',5,'multiple_choice','Galaxy Z Fold','جالاكسي زد فولد','Galaxy S','جالاكسي إس','Galaxy Note','جالاكسي نوت','Galaxy A','جالاكسي إيه','A',NULL,NULL,NULL,'2025-11-10 16:34:35'),(133,42,'What is Orange Egypt promoting?','ماذا تروج أورانج مصر؟',1,'multiple_choice','Best iPhone prices',NULL,'Free data',NULL,'New network',NULL,'SIM cards',NULL,'A',NULL,NULL,NULL,'2025-11-11 21:33:04'),(134,42,'What color is associated with Orange brand?','ما اللون المرتبط بعلامة أورانج التجارية؟',2,'multiple_choice','Red',NULL,'Blue',NULL,'Orange',NULL,'Green',NULL,'C',NULL,NULL,NULL,'2025-11-11 21:33:04'),(135,42,'What type of service does Orange provide?','ما نوع الخدمة التي تقدمها أورانج؟',3,'multiple_choice','Banking',NULL,'Telecommunications',NULL,'Insurance',NULL,'Real Estate',NUL